const html = $json.data || '';
const lead_id = $('Get CF Profiles').item.json.lead_id;
const username = $('Get CF Profiles').item.json.username;

function extract(html, regex, group) {
  group = group || 1;
  const m = html.match(regex);
  return m ? m[group].trim() : null;
}

function extractNum(str) {
  if (!str) return 0;
  const m = str.match(/(\d+)/);
  return m ? parseInt(m[1]) : 0;
}

const currentRating = extractNum(extract(html, /Contest rating:<\/li>\s*<li[^>]*><span[^>]*>(\d+)<\/span>/));
const maxRating = extractNum(extract(html, /\(max\.\s*<span[^>]*>[^,]*,\s*(\d+)/));
const rank = extract(html, /class="user-rank">\s*<span[^>]*>([^<]+)<\/span>/) || '';

const counterValues = [];
const counterDescs = [];
const valRegex = /_UserActivityFrame_counterValue">([^<]+)<\/div>/g;
const descRegex = /_UserActivityFrame_counterDescription">\s*([^<]+?)\s*<\/div>/g;
let m;
while ((m = valRegex.exec(html)) !== null) counterValues.push(m[1].trim());
while ((m = descRegex.exec(html)) !== null) counterDescs.push(m[1].trim());

const activity = {};
for (let i = 0; i < counterValues.length && i < counterDescs.length; i++) {
  const desc = counterDescs[i].toLowerCase();
  const val = counterValues[i];
  if (desc.indexOf('all time') >= 0) activity.problems_all_time = extractNum(val);
  else if (desc.indexOf('last year') >= 0 && desc.indexOf('solved') >= 0) activity.problems_last_year = extractNum(val);
  else if (desc.indexOf('last month') >= 0 && desc.indexOf('solved') >= 0) activity.problems_last_month = extractNum(val);
  else if (desc.indexOf('row max') >= 0) activity.streak_max = extractNum(val);
  else if (desc.indexOf('row') >= 0 && desc.indexOf('last year') >= 0) activity.streak_last_year = extractNum(val);
  else if (desc.indexOf('row') >= 0 && desc.indexOf('last month') >= 0) activity.streak_last_month = extractNum(val);
}

const contribution = extractNum(extract(html, /Contribution:<\/span>\s*<span[^>]*>([^<]+)<\/span>/));
const friendOf = extractNum(extract(html, /Friend of:\s*<span[^>]*>(\d+)/));
var avatar = extract(html, /class="title-photo"[^>]*>\s*<img[^>]*src="([^"]+)"/) || '';
if (avatar.indexOf('//') === 0) avatar = 'https:' + avatar;

return {
  json: {
    lead_id: lead_id,
    raw_json: {
      user: {
        handle: username,
        rating: currentRating || null,
        maxRating: maxRating || null,
        rank: rank || null,
        avatar: avatar,
        contribution: contribution || 0,
        friendOfCount: friendOf || 0
      },
      activity: activity,
      submissions: [],
      ratingHistory: []
    },
    fetched_at: new Date().toISOString()
  }
};
